<script setup>
import { ref } from 'vue'
import { router, useForm } from '@inertiajs/vue3'
import AppLayout from '@/Layouts/AppLayout.vue'
import BaseCard from '@/Components/BaseCard.vue'
import DataTable from '@/Components/DataTable.vue'
import PageHeader from '@/Components/PageHeader.vue'
import { confirmDanger } from '@/Composables/useNotifications'

const props = defineProps({ records: Object, filters: Object, files: Array })
const equipmentFilter = ref(props.filters?.equipment_file_id || '')
const showModal = ref(false)
const editing = ref(null)
const query = new URLSearchParams(window.location.search)
const form = useForm({ equipment_file_id: equipmentFilter.value || '', incident_date: new Date().toISOString().slice(0,10), incident_time: '', area: query.get('area') || '', consecutive_number: '', detected_fact: '', detection_method: '', measures_taken: '', observations: '' })
const columns = [{key:'incident_date',label:'Fecha'},{key:'equipment',label:'Expediente'},{key:'detected_fact',label:'Hecho detectado'},{key:'measures_taken',label:'Medidas'},{key:'actions',label:'Acciones'}]
const applyFilter = () => router.get('/incidencias-seguridad', { equipment_file_id: equipmentFilter.value || undefined }, { preserveState:true, replace:true })
const openCreate = () => { editing.value=null; form.reset(); form.equipment_file_id = equipmentFilter.value || ''; form.incident_date = new Date().toISOString().slice(0,10); form.area = query.get('area') || ''; form.clearErrors(); showModal.value=true }
const openEdit = (row) => { editing.value=row; Object.assign(form,{ equipment_file_id: row.equipment_file_id, incident_date: row.incident_date, incident_time: row.incident_time || '', area: row.area || '', consecutive_number: row.consecutive_number || '', detected_fact: row.detected_fact, detection_method: row.detection_method || '', measures_taken: row.measures_taken || '', observations: row.observations || '' }); form.clearErrors(); showModal.value=true }
const submit = () => editing.value ? form.put(`/incidencias-seguridad/${editing.value.id}`, { onSuccess:()=> showModal.value=false }) : form.post('/incidencias-seguridad', { onSuccess:()=> showModal.value=false })
const destroy = async (row) => { if (!await confirmDanger({ title:'Eliminar incidencia', text:'Se eliminara la incidencia de seguridad.', confirmText:'Si, eliminar' })) return; router.delete(`/incidencias-seguridad/${row.id}`) }
</script>
<template><AppLayout><div class="mx-auto max-w-7xl space-y-6"><PageHeader eyebrow="Historial" title="Incidencias de Seguridad" description="Registro cronologico de hechos detectados, medidas y observaciones."><template #actions><button class="app-button-primary" @click="openCreate">Nueva incidencia</button></template></PageHeader><BaseCard><select v-model="equipmentFilter" class="app-select max-w-md" @change="applyFilter"><option value="">Todos los expedientes</option><option v-for="file in files" :key="file.id" :value="file.id">{{ file.file_number }} - {{ file.inventory_number }}</option></select></BaseCard><DataTable client-table :columns="columns" :data="records"><template #cell-equipment="{ row }"><div><p class="font-medium text-slate-900 dark:text-slate-100">{{ row.equipment_file?.file_number }}</p><p class="text-xs text-slate-500 dark:text-slate-400">{{ row.area || row.equipment_file?.inventory_number }}</p></div></template><template #cell-detected_fact="{ row }"><span class="text-slate-700 dark:text-slate-200">{{ row.detected_fact }}</span></template><template #cell-measures_taken="{ row }"><span class="text-slate-700 dark:text-slate-200">{{ row.measures_taken || '-' }}</span></template><template #cell-actions="{ row }"><div class="flex justify-end gap-2"><button class="app-button-secondary px-3 py-2 text-xs" @click="openEdit(row)">Editar</button><button class="app-button-danger px-3 py-2 text-xs" @click="destroy(row)">Eliminar</button></div></template></DataTable></div><Teleport to="body"><div v-if="showModal" class="fixed inset-0 z-50 flex items-center justify-center px-4"><div class="fixed inset-0 bg-slate-950/70 backdrop-blur-sm" @click="showModal=false" /><div class="surface-card relative z-10 w-full max-w-4xl p-6"><h3 class="mb-5 text-xl font-semibold text-slate-950 dark:text-slate-100">{{ editing ? 'Editar incidencia' : 'Nueva incidencia' }}</h3><form class="space-y-5" @submit.prevent="submit"><div class="grid gap-5 md:grid-cols-4"><select v-model="form.equipment_file_id" class="app-select"><option value="">Expediente...</option><option v-for="file in files" :key="file.id" :value="file.id">{{ file.file_number }}</option></select><input v-model="form.incident_date" type="date" class="app-input" /><input v-model="form.incident_time" type="time" class="app-input" /><input v-model="form.consecutive_number" type="text" class="app-input" placeholder="Consecutivo" /></div><input v-model="form.area" type="text" class="app-input" placeholder="Area" /><textarea v-model="form.detected_fact" rows="3" class="app-input" placeholder="Hecho detectado"></textarea><textarea v-model="form.detection_method" rows="2" class="app-input" placeholder="Forma de deteccion"></textarea><textarea v-model="form.measures_taken" rows="2" class="app-input" placeholder="Medidas tomadas"></textarea><textarea v-model="form.observations" rows="2" class="app-input" placeholder="Observaciones"></textarea><div class="flex justify-end gap-3 border-t border-slate-200/80 pt-4 dark:border-slate-800"><button type="button" class="app-button-secondary" @click="showModal=false">Cancelar</button><button type="submit" class="app-button-primary" :disabled="form.processing">{{ form.processing ? 'Guardando...' : 'Guardar' }}</button></div></form></div></div></Teleport></AppLayout></template>
